SELECT username, email
FROM users
WHERE user_id NOT IN (
    SELECT DISTINCT author_id
    FROM content
) AND user_id NOT IN (
    SELECT DISTINCT user_id
    FROM comments
);

SELECT user_id 
FROM users 
WHERE user_id IN (
  SELECT organizer_id FROM events
) 
AND user_id NOT IN (
  SELECT author_id FROM content
);

SELECT DISTINCT u.username, u.email, u.role, u.created_at
FROM users u
INNER JOIN content c ON u.user_id = c.author_id;
